// Tests for explicit FRF over RGB channels. Verifies splitRGB/joinRGB
// round-trip, channel extraction order, identity / scaling / async
// transforms, channelIndex routing, and validation.

import { describe, it, expect } from 'vitest';
import { splitRGB, joinRGB, rgbFRF } from '../src/image-rgb-frf';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function randomRGB(width: number, height: number, seed: number): Float32Array {
  const out = new Float32Array(width * height * 3);
  const rand = lcg(seed);
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

function maxAbsDelta(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch ${a.length} vs ${b.length}`);
  }
  let m = 0;
  for (let i = 0; i < a.length; i++) {
    const d = Math.abs(a[i] - b[i]);
    if (d > m) m = d;
  }
  return m;
}

function rmse(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch ${a.length} vs ${b.length}`);
  }
  let s = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i] - b[i];
    s += d * d;
  }
  return Math.sqrt(s / a.length);
}

describe('splitRGB / joinRGB round-trip', () => {
  it('round-trips a 4x4 random RGB plane exactly', () => {
    const w = 4,
      h = 4;
    const data = randomRGB(w, h, 0xc0ffee);
    const [r, g, b] = splitRGB({ data, width: w, height: h });
    const joined = joinRGB({ channels: [r, g, b], width: w, height: h });
    expect(joined.length).toBe(data.length);
    expect(maxAbsDelta(joined, data)).toBe(0);
  });
});

describe('splitRGB extracts the right channels', () => {
  it('pulls R, G, B out of an interleaved plane', () => {
    // 2x1 plane: pixel0=(r0,g0,b0), pixel1=(r1,g1,b1)
    const data = new Float32Array([
      0.10, 0.20, 0.30,
      0.40, 0.50, 0.60,
    ]);
    const [r, g, b] = splitRGB({ data, width: 2, height: 1 });
    expect(Array.from(r)).toEqual([
      Math.fround(0.10),
      Math.fround(0.40),
    ]);
    expect(Array.from(g)).toEqual([
      Math.fround(0.20),
      Math.fround(0.50),
    ]);
    expect(Array.from(b)).toEqual([
      Math.fround(0.30),
      Math.fround(0.60),
    ]);
  });
});

describe('rgbFRF identity transform', () => {
  it('passes 8x8 plane through unchanged', async () => {
    const w = 8,
      h = 8;
    const data = randomRGB(w, h, 0xdeadbeef);
    const out = await rgbFRF({
      data,
      width: w,
      height: h,
      transform: (ch) => ch,
    });
    expect(out.length).toBe(data.length);
    expect(rmse(out, data)).toBe(0);
  });
});

describe('rgbFRF doubles each channel', () => {
  it('produces bit-equal input * 2', async () => {
    const w = 8,
      h = 8;
    const data = randomRGB(w, h, 1234);
    const out = await rgbFRF({
      data,
      width: w,
      height: h,
      transform: (ch) => new Float32Array(ch.map((v) => v * 2)),
    });
    const expected = new Float32Array(data.length);
    for (let i = 0; i < data.length; i++) expected[i] = data[i] * 2;
    expect(out.length).toBe(expected.length);
    expect(maxAbsDelta(out, expected)).toBe(0);
  });
});

describe('rgbFRF with async transform', () => {
  it('awaits the transform Promise correctly', async () => {
    const w = 4,
      h = 4;
    const data = randomRGB(w, h, 99);
    const out = await rgbFRF({
      data,
      width: w,
      height: h,
      transform: async (ch) => {
        // Simulate async work.
        await Promise.resolve();
        return new Float32Array(ch.map((v) => v * 0.5));
      },
    });
    const expected = new Float32Array(data.length);
    for (let i = 0; i < data.length; i++) expected[i] = data[i] * 0.5;
    expect(maxAbsDelta(out, expected)).toBe(0);
  });
});

describe('rgbFRF channelIndex parameter', () => {
  it('routes the correct index to each channel', async () => {
    const w = 4,
      h = 4;
    const data = new Float32Array(w * h * 3); // zeros; transform overwrites
    const out = await rgbFRF({
      data,
      width: w,
      height: h,
      transform: (ch, _w, _h, idx) =>
        new Float32Array(ch.length).fill(
          idx === 0 ? 0.1 : idx === 1 ? 0.5 : 0.9,
        ),
    });
    // Verify each pixel: R=0.1, G=0.5, B=0.9
    for (let i = 0; i < w * h; i++) {
      const j = i * 3;
      expect(out[j]).toBeCloseTo(0.1, 6);
      expect(out[j + 1]).toBeCloseTo(0.5, 6);
      expect(out[j + 2]).toBeCloseTo(0.9, 6);
    }
  });
});

describe('rgbFRF validation', () => {
  it('throws on bad data length', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(10), // not 4*4*3=48
        width: 4,
        height: 4,
        transform: (ch) => ch,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on zero width', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(0),
        width: 0,
        height: 4,
        transform: (ch) => ch,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on zero height', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(0),
        width: 4,
        height: 0,
        transform: (ch) => ch,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on negative width', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(48),
        width: -4,
        height: 4,
        transform: (ch) => ch,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on bad concurrency (zero)', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(48),
        width: 4,
        height: 4,
        transform: (ch) => ch,
        concurrency: 0,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on non-integer concurrency', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(48),
        width: 4,
        height: 4,
        transform: (ch) => ch,
        concurrency: 1.5,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('throws on non-function transform', async () => {
    await expect(
      rgbFRF({
        data: new Float32Array(48),
        width: 4,
        height: 4,
        // @ts-expect-error testing bad input
        transform: 'not a function',
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('splitRGB throws on bad data length', () => {
    expect(() =>
      splitRGB({ data: new Float32Array(5), width: 2, height: 2 }),
    ).toThrow(RangeError);
  });

  it('joinRGB throws when channels.length !== 3', () => {
    expect(() =>
      joinRGB({
        channels: [new Float32Array(4), new Float32Array(4)],
        width: 2,
        height: 2,
      }),
    ).toThrow(RangeError);
  });

  it('joinRGB throws when a channel has wrong length', () => {
    expect(() =>
      joinRGB({
        channels: [
          new Float32Array(4),
          new Float32Array(3),
          new Float32Array(4),
        ],
        width: 2,
        height: 2,
      }),
    ).toThrow(RangeError);
  });
});
